--on cp message
function LSdkCpAvg:OnLoginResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        local jsondata = args[2]
        local data = JSON.decode(jsondata)
        self._loginData = data
        self._sUserId = ""
        self:GetUserInfo()
    else
        self._sUserId = ""

        self:LoginFailure()
    end
end

function LSdkCpAvg:OnLogoutResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        local sUserId = args[2]
        if sUserId == self._sUserId then
            self._isValidUser = false
            self._sUserId = ""
            self:LogoutOk()
        end
    end
end

