function LSdkCpAvg:OnUserInfoResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        local jsondata = args[2]
        local data = JSON.decode(jsondata)
        self._sUserId = data.userId
        LNativeHelper.SetReportUserId(self._sUserId)
        self._isValidUser = true
        self:LoginOk()
    else
        self._sUserId = ""
        self:LoginFailure()
    end
end

